-- Live compliance: obligations (rule library) + per-tenant status
\connect cyberwatch
CREATE TABLE IF NOT EXISTS grc.obligations (
  id text PRIMARY KEY, framework text, clause text, requirement text, applicability text, cadence text,
  control text, module text, evidence_expected text, phase text, auto_key text, sort int
);
CREATE TABLE IF NOT EXISTS grc.compliance_status (
  tenant_id uuid NOT NULL,
  obligation_id text NOT NULL REFERENCES grc.obligations(id),
  status text NOT NULL DEFAULT 'Not Assessed',
  owner text, notes text,
  evidence_refs jsonb NOT NULL DEFAULT '[]'::jsonb,
  updated_by text, updated_at timestamptz NOT NULL DEFAULT now(),
  PRIMARY KEY (tenant_id, obligation_id)
);
ON CONFLICT (id) DO UPDATE SET framework=EXCLUDED.framework, clause=EXCLUDED.clause, requirement=EXCLUDED.requirement,
  applicability=EXCLUDED.applicability, cadence=EXCLUDED.cadence, control=EXCLUDED.control, module=EXCLUDED.module,
  evidence_expected=EXCLUDED.evidence_expected, phase=EXCLUDED.phase, auto_key=EXCLUDED.auto_key, sort=EXCLUDED.sort;
